const METADATA_TAG = "---LEVRIX_METADATA---";

const DEFAULT_INTEGRATIONS: Integrations = {
  email: { enabled: false, provider: 'sendgrid', apiKey: '', fromEmail: '', connected: false },
  sms: { 
    enabled: false, 
